import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import './Sidebar.css';

const Sidebar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const isAdmin = user?.role === 'admin';

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  // Customer Navigation Items
  const customerNavItems = [
    { name: 'Dashboard', path: '/customer/dashboard', icon: '📊' },
    { name: 'Transactions', path: '/customer/transactions', icon: '📝' },
    { name: 'Ratings', path: '/customer/ratings', icon: '⭐' },
    { name: 'Returns', path: '/customer/returns', icon: '↩️' },
    { name: 'Messages', path: '/customer/messages', icon: '💬' },
    { name: 'Profile', path: '/customer/profile', icon: '👤' },
  ];

  // Admin Navigation Items
  const adminNavItems = [
    { name: 'Dashboard', path: '/admin/dashboard', icon: '📊' },
    { name: 'Sensors', path: '/admin/sensors', icon: '📡' },
    { name: 'Transactions', path: '/admin/transactions', icon: '📝' },
    { name: 'Returns', path: '/admin/returns', icon: '↩️' },
    { name: 'Ratings', path: '/admin/ratings', icon: '⭐' },
    { name: 'Messages', path: '/admin/messages', icon: '💬' },
    { name: 'Reports', path: '/admin/reports', icon: '📈' },
    { name: 'Users', path: '/admin/users', icon: '👥' },
  ];

  const navItems = isAdmin ? adminNavItems : customerNavItems;

  // Check if user is authenticated
  if (!user) {
    return null;
  }

  return (
    <aside className="sidebar">
      <div className="sidebar-header">
        <div className="sidebar-logo">
          <h2>AgriVend</h2>
          <p>{isAdmin ? 'Admin Panel' : 'Customer Portal'}</p>
        </div>
      </div>
      
      <nav className="sidebar-nav">
        {navItems.map((item) => (
          <NavLink
            key={item.path}
            to={item.path}
            className={({ isActive }) => 
              `sidebar-link ${isActive ? 'active' : ''}`
            }
            end={item.path === (isAdmin ? '/admin/dashboard' : '/customer/dashboard')}
          >
            <span className="link-icon">{item.icon}</span>
            <span className="link-name">{item.name}</span>
          </NavLink>
        ))}
      </nav>

      <div className="sidebar-footer">
        <div className="user-info">
          <div className="user-avatar">
            {user?.firstName?.charAt(0)}{user?.lastName?.charAt(0)}
          </div>
          <div className="user-details">
            <div className="user-name">{user?.firstName} {user?.lastName}</div>
            <div className="user-email">{user?.email}</div>
          </div>
        </div>
        <button onClick={handleLogout} className="logout-btn">
          <span>🚪</span>
          Logout
        </button>
      </div>
    </aside>
  );
};

export default Sidebar;
